INSERT INTO examples (name, category, framework, files, dependencies, metadata) VALUES ('"corner-ribbon"', '"Prsnt"', '"vanilla"', '{"demo.css": ".corner-ribbon {\n  position: relative;\n}\n\n.corner-ribbon__inner {\n  /* Displayed at the top left corner */\n  left: 0px;\n  position: absolute;\n  top: 0px;\n\n  /* Size */\n  height: 4rem;\n  width: 4rem;\n\n  /* Hide the part of its children which is displayed outside */\n  overflow: hidden;\n}\n\n.corner-ribbon__ribbon {\n  /* Position */\n  left: 1rem;\n  position: absolute;\n  top: 1rem;\n\n  /* Size */\n  height: 1.5rem;\n  width: 5.656rem;\n\n  /* Displayed diagonally */\n  transform: translate(-38px, -8px) rotate(-45deg);\n\n  /* Background color */\n  background-color: #d1d5db;\n\n  /* Centerize the text content */\n  text-align: center;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Static Template\r\n    </h1>\r\n    <div class=\"corner-ribbon\">\r\n      <!-- The container -->\r\n      <div class=\"corner-ribbon__inner\">\r\n        <!-- The ribbon -->\r\n        <div class=\"corner-ribbon__ribbon\"></div>\r\n      </div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/corner-ribbon"}'), ('"counter"', '"Prsnt"', '"vanilla"', '{"demo.css": "ul {\n  counter-reset: counter;\n  list-style: none;\n}\n\nli::before {\n  counter-increment: counter;\n  content: counters(counter, ''.'') '' '';\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Counter\r\n    </h1>\r\n    <ul>\r\n      <li>List item</li>\r\n      <li>List item</li>\r\n      <li>\r\n        List item\r\n        <ul>\r\n          <li>List item</li>\r\n          <li>List item</li>\r\n          <li>List item</li>\r\n        </ul>\r\n      </li>\r\n    </ul>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/counter"}'), ('"curved-background"', '"Prsnt"', '"vanilla"', '{"demo.css": ".curved-background__curved {\n  /* Background color */\n  background-color: #d1d5db;\n\n  /* You can use gradient background color such as */\n  /* background: linear-gradient(rgba(0, 0, 0, 0.2) 0%, rgba(0, 0, 0, 0.1) 100%); */\n\n  /* Curved corners */\n  border-bottom-left-radius: 50% 40%;\n  border-bottom-right-radius: 50% 40%;\n\n  /* Size */\n  height: 50%;\n  width: 100%;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Curved Background\r\n    </h1>\r\n    <div class=\"curved-background\">\r\n      <div class=\"curved-background__curved\">Curved Background</div>\r\n    </div>\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/curved-background"}'), ('"diagnal-section"', '"Prsnt"', '"vanilla"', '{"demo.css": ".diagonal-section {\n  /* Used to position the diagonal area */\n  position: relative;\n}\n\n.diagonal-section__diagonal {\n  /* Absolute position */\n  left: 0px;\n  position: absolute;\n  top: 0px;\n\n  /* Take full size */\n  height: 100%;\n  width: 100%;\n\n  /* Create diagonal sides */\n  transform: skewY(-5deg);\n\n  /* Background color */\n  background-color: #d1d5db;\n\n  /* Displayed under the main content */\n  z-index: -1;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Diagnal Section\r\n    </h1>\r\n    <div class=\"diagonal-section\">\r\n      <!-- The diagonal area -->\r\n      <div class=\"diagonal-section__diagonal\"></div>\r\n\r\n      <!-- Content -->\r\n      Content\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/diagnal-section"}'), ('"disclosure"', '"Prsnt"', '"vanilla"', '{"demo.css": "/**\n * 1. Styling for Firefox and other non-webkit/blink browsers\n * 2. Styling for webkit and blink\n */\n\nsummary, /* 1 */\nsummary::-webkit-details-marker {\n  /* 2 */\n  list-style-image: url(\"\");\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Disclosure\r\n    </h1>\r\n    <details>\r\n      <summary>The toggle</summary>\r\n      The content.\r\n    </details>\r\n\r\n    <details open>\r\n      <summary>Another toggle</summary>\r\n      Expanded by default\r\n    </details>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/disclosure"}'), ('"docked-at-corner"', '"Prsnt"', '"vanilla"', '{"demo.css": ".docked-at-corner {\n  position: relative;\n}\n.docked-at-corner__docker {\n  position: absolute;\n  right: 0;\n  top: 0;\n  transform: translate(50%, -50%);\n\n  /* Center the content */\n  align-items: center;\n  display: flex;\n  justify-content: center;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Docked At Corner\r\n    </h1>\r\n    <div class=\"docked-at-corner\">\r\n      <!-- Docked at the top right corner -->\r\n      <div class=\"docked-at-corner__docker\">Docked</div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/docked-at-corner"}'), ('"dot-leader"', '"Prsnt"', '"vanilla"', '{"demo.css": ".dot-leader {\n  /* Center the content */\n  align-items: center;\n  display: flex;\n  justify-content: center;\n}\n\n.dot-leader__dots {\n  /* Bottom border */\n  border-bottom: 1px dotted #d1d5db;\n\n  /* Take remaining width */\n  flex: 1;\n\n  /* Spacing */\n  margin: 0 0.25rem;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Dot Leader\r\n    </h1>\r\n    <div class=\"dot-leader\">\r\n      <!-- Left side -->\r\n      <div>Left</div>\r\n\r\n      <!-- Dots -->\r\n      <div class=\"dot-leader__dots\"></div>\r\n\r\n      <!-- Right side -->\r\n      <div>Right</div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/dot-leader"}'), ('"drop-area"', '"Prsnt"', '"vanilla"', '{"demo.css": ".drop-area {\n  /* Center the content */\n  align-items: center;\n  display: flex;\n  justify-content: center;\n\n  /* Border */\n  border: 0.25rem dashed #d1d5db;\n  border-radius: 0.25rem;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Drop area</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Drop area\r\n    </h1>\r\n    <div class=\"drop-area\">Drop Area</div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/drop-area"}'), ('"drop-cap"', '"Prsnt"', '"vanilla"', '{"demo.css": "p:first-child::first-letter {\n  color: #5f79ff;\n  float: left;\n  margin: 0 8px 0 4px;\n  font-size: 3rem;\n  font-weight: bold;\n  line-height: 1;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Static Template\r\n    </h1>\r\n    <p>\r\n      Lorem ipsum dolor sit amet, consectetur adipiscing elit. Aliquam commodo\r\n      ligula quis tincidunt cursus. Integer consectetur tempor ex eget\r\n      hendrerit. Cras facilisis sodales odio nec maximus. Pellentesque lacinia\r\n      convallis libero, rhoncus tincidunt ante dictum at. Nullam facilisis\r\n      lectus tellus, sit amet congue erat sodales commodo.\r\n    </p>\r\n    <p>\r\n      Donec magna erat, imperdiet non odio sed, sodales tempus magna. Integer\r\n      vitae orci lectus. Nullam consectetur orci at pellentesque efficitur.\r\n    </p>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/drop-cap"}'), ('"f39dhx"', '"Prsnt"', '"vanilla"', '{"demo.css": ".lined-paper {\n  /* Lined background */\n  background-image: linear-gradient(#d1d5db 1px, transparent 0px);\n  background-size: 100% 2em;\n\n  /*\n    Display the content on top of the lines.\n    The line height must be the same as the background size defined above\n    */\n  background-position-y: 1.5rem;\n  line-height: 2em;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Static Template\r\n    </h1>\r\n    <div class=\"lined-paper\">Line 1</div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/f39dhx"}'), ('"fading-long-section"', '"Prsnt"', '"vanilla"', '{"demo.css": ".fading-long-section {\n  /* Used to position the faded element */\n  position: relative;\n}\n\n.fading-long-section__content {\n  /* Height */\n  height: 100%;\n  overflow-y: hidden;\n}\n\n.fading-long-section__fading {\n  /* Displayed at the bottom */\n  bottom: 0;\n  left: 0;\n  position: absolute;\n\n  /* Size */\n  height: 2rem;\n  width: 100%;\n\n  /* Gradient background */\n  background: linear-gradient(rgba(255, 255, 255, 0.01), #fff);\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Static Template\r\n    </h1>\r\n    <div class=\"fading-long-section\">\r\n      <!-- Main content -->\r\n      <div class=\"fading-long-section__content\">Content</div>\r\n\r\n      <!-- The faded element -->\r\n      <div class=\"fading-long-section__fading\"></div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/fading-long-section"}'), ('"feature-comparison"', '"Prsnt"', '"vanilla"', '{"demo.css": ".feature-comparison {\n  align-items: center;\n  display: flex;\n\n  /* Bottom border */\n  border-bottom: 1px solid #d1d5db;\n\n  /* Spacing */\n  padding: 0.25rem 0;\n}\n\n.feature-comparison__feature {\n  /* Take available width */\n  flex: 1;\n}\n\n.feature-comparison__model {\n  /* Center the content */\n  display: flex;\n  justify-content: center;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Feature Comparison\r\n    </h1>\r\n    <div class=\"feature-comparison\">\r\n      <!-- Feature name -->\r\n      <div class=\"feature-comparison__feature\">Name</div>\r\n\r\n      <!-- The model -->\r\n      <div class=\"feature-comparison__model\">\r\n        <!--\r\n            For the first row: display the model name (Basic, Pro, etc.)\r\n            From the second row: display a yes/no icon indicating the feature is available or not\r\n            -->\r\n      </div>\r\n\r\n      <!-- Repeated other models -->\r\n      Repeated other models\r\n    </div>\r\n\r\n    <!-- Repeated items -->\r\n    Repeated Items\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/feature-comparison"}'), ('"feature-list"', '"Prsnt"', '"vanilla"', '{"demo.css": ".feature-list {\n  display: flex;\n\n  /* OPTIONAL: Spacing between items */\n  margin: 0.5rem 0;\n}\n\n/* Reverse the order of image and content */\n.feature-list--reverse {\n  flex-direction: row-reverse;\n}\n\n.feature-list__image {\n  width: 2rem;\n}\n\n.feature-list__desc {\n  /* Take the remaining width */\n  flex: 1;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Featrue List\r\n    </h1>\r\n    <!-- Feature item -->\r\n    <div class=\"feature-list\">\r\n      <!-- Image -->\r\n      <div class=\"feature-list__image\">Img</div>\r\n\r\n      <!-- Right side -->\r\n      <div class=\"feature-list__desc\">Desc</div>\r\n    </div>\r\n\r\n    <!-- Repeated items -->\r\n    Repeated Items\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/feature-list"}'), ('"fixed-at-corner"', '"Prsnt"', '"vanilla"', '{"demo.css": ".fixed-at-corner {\n  position: relative;\n}\n\n.fixed-at-corner__corner {\n  position: absolute;\n}\n\n.fixed-at-corner__corner--tl {\n  left: 0;\n  top: 0;\n}\n\n.fixed-at-corner__corner--tr {\n  top: 0;\n  right: 0;\n}\n\n.fixed-at-corner__corner--br {\n  bottom: 0;\n  right: 0;\n}\n\n.fixed-at-corner__corner--bl {\n  bottom: 0;\n  left: 0;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Fixed At Corner\r\n    </h1>\r\n    <div class=\"fixed-at-corner\">\r\n      <!-- Top-left corner -->\r\n      <div class=\"fixed-at-corner__corner fixed-at-corner__corner--tl\">\r\n        Top Left\r\n      </div>\r\n\r\n      <!-- Top-right corner -->\r\n      <div class=\"fixed-at-corner__corner fixed-at-corner__corner--tr\">\r\n        Top Right\r\n      </div>\r\n\r\n      <!-- Bottom-right corner -->\r\n      <div class=\"fixed-at-corner__corner fixed-at-corner__corner--br\">\r\n        Bottom Right\r\n      </div>\r\n\r\n      <!-- Bottom-left corner -->\r\n      <div class=\"fixed-at-corner__corner fixed-at-corner__corner--bl\">\r\n        Bottom Left\r\n      </div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/fixed-at-corner"}'), ('"fixed-at-side"', '"Prsnt"', '"vanilla"', '{"demo.css": ".fixed-at-side {\n  position: fixed;\n  top: 50%;\n  transform: translate(0px, -50%);\n}\n.fixed-at-side--l {\n  left: 0;\n}\n.fixed-at-side--r {\n  right: 0;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Fixed At Side\r\n    </h1>\r\n    <!-- Fixed at the middle of left side -->\r\n    <div class=\"fixed-at-side fixed-at-side--l\">Left</div>\r\n\r\n    <!-- Fixed at the middle of right side -->\r\n    <div class=\"fixed-at-side fixed-at-side--r\">Right</div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/fixed-at-side"}'), ('"folder-structure"', '"Prsnt"', '"vanilla"', '{"demo.css": ":root {\n  --folder-structure-item-height: 0.5rem;\n  --folder-structure-item-margin-left: 2.25rem;\n  --folder-structure-item-padding-top: 0.5rem;\n}\n\n.folder-structure ul {\n  /* Reset */\n  list-style-type: none;\n  margin: 0;\n}\n\n.folder-structure li {\n  padding: var(--folder-structure-item-padding-top) 0rem 0rem 0rem;\n  position: relative;\n}\n\n.folder-structure li::before {\n  border-left: 1px solid #d1d5db;\n  content: \"\";\n\n  /* Position */\n  left: 0;\n  position: absolute;\n  top: 0;\n  transform: translate(calc(-1 * var(--folder-structure-item-margin-left)), 0);\n\n  /* Size */\n  height: 100%;\n}\n\n.folder-structure li::after {\n  border-bottom: 1px solid #d1d5db;\n  content: \"\";\n\n  /* Position */\n  left: 0;\n  position: absolute;\n  top: calc(\n    var(--folder-structure-item-padding-top) +\n      var(--folder-structure-item-height) / 2\n  );\n  transform: translate(-100%, 0);\n\n  /* Size */\n  width: var(--folder-structure-item-margin-left);\n}\n\n/* Remove the border from the last item */\n.folder-structure li:last-child::before {\n  height: calc(\n    var(--folder-structure-item-padding-top) +\n      var(--folder-structure-item-height) / 2\n  );\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Folder Structure\r\n    </h1>\r\n    <div class=\"folder-structure\">\r\n      <ul>\r\n        <li>\r\n          <!-- Content -->\r\n          ...\r\n\r\n          <!-- Sub items -->\r\n          <ul>\r\n            <li>\r\n              <!-- Content -->\r\n              ...\r\n\r\n              <!-- Sub items -->\r\n              <ul>\r\n                <li>...</li>\r\n                <li>...</li>\r\n                ...\r\n              </ul>\r\n            </li>\r\n            <li>...</li>\r\n            ...\r\n          </ul>\r\n        </li>\r\n\r\n        <!-- Repeat other items -->\r\n        ...\r\n      </ul>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/folder-structure"}'), ('"full-background"', '"Prsnt"', '"vanilla"', '{"demo.css": ".full-background {\n  /* Center the content */\n  align-items: center;\n  display: flex;\n  flex-direction: column;\n  justify-content: center;\n\n  /* Take full size */\n  height: 100vh;\n  width: 100%;\n\n  /* Background */\n  background: url(\"/assets/full-background.jpeg\") center center / cover\n    no-repeat;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Full Background\r\n    </h1>\r\n    <div class=\"full-background\">Background</div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/full-background"}'), ('"initial-avatar"', '"Prsnt"', '"vanilla"', '{"demo.css": ".initial-avatar {\n  /* Center the content */\n  align-items: center;\n  display: flex;\n  justify-content: center;\n\n  /* Colors */\n  background-color: #d1d5db;\n  color: #fff;\n\n  /* Rounded border */\n  border-radius: 50%;\n  height: 3rem;\n  width: 3rem;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Initial Avatar\r\n    </h1>\r\n    <div class=\"initial-avatar\">...</div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/initial-avatar"}'), ('"inverted-corner"', '"Prsnt"', '"vanilla"', '{"demo.css": ":root {\n  --inverted-corners-background: #d1d5db;\n  --inverted-corners-size: 2rem;\n}\n\n.inverted-corners {\n  background-color: var(--inverted-corners-background);\n\n  /* Used to position the corner */\n  position: relative;\n}\n\n.inverted-corners::before {\n  content: \"\";\n\n  /* Absolute position */\n  bottom: calc(-2 * var(--inverted-corners-size));\n  left: 0;\n  position: absolute;\n\n  /* Size */\n  height: calc(2 * var(--inverted-corners-size));\n  width: var(--inverted-corners-size);\n\n  /* Border */\n  background-color: transparent;\n  border-top-left-radius: var(--inverted-corners-size);\n  box-shadow: var(--inverted-corners-background) 0px\n    calc(-1 * var(--inverted-corners-size)) 0px 0px;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Inverted Corner\r\n    </h1>\r\n    <div class=\"inverted-corners\">...</div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/inverted-corner"}'), ('"keyboard-shortcut"', '"Prsnt"', '"vanilla"', '{"demo.css": ".keyboard-shortcut {\n  /* Background and color */\n  background-color: rgba(0, 0, 0, 0.1);\n  border-radius: 0.25rem;\n  color: rgba(0, 0, 0, 0.7);\n\n  /* Bottom shadow */\n  box-shadow: #d1d5db 0px -4px 0px inset, rgba(0, 0, 0, 0.4) 0px 1px 1px;\n\n  /* Spacing */\n  padding: 0.25rem 0.5rem;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Keyboard Shortcut\r\n    </h1>\r\n    <kbd class=\"keyboard-shortcut\">...</kbd>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/keyboard-shortcut"}');